from __future__ import annotations

import base64
import re
from pathlib import Path

MINER_FILE = Path("BedrockAddonMinerFullSource_398f9151d066_001.txt")

ASSETS = {
    "Township BP/pack_icon.png": "",
    "Township RP/pack_icon.png": "",
    "Township RP/textures/blocks/township_build_recorder.png": "",
    "Township RP/textures/blocks/township_dirt_road.png": "",
    "Township RP/textures/blocks/township_founding_stone.png": "",
    "Township RP/textures/blocks/township_ground_leveler.png": "iVBORw0KGgoAAAANSUhEUgAAABAAAAAQCAYAAAAf8/9hAAAAhUlEQVR4nGMMiLf5z0ABYJFTkKBEPwPLowcv8CroKbZhKOk9glOeMa8+BO6FvGAVomydtPYOLheoYNiG7oKeYhsGZD0YYYAtTPCpwXABZpigi6lQ1wWMsHTQU2yDoREfgIULRiwghzA2MXT+wIcBhguwJSZ0MWQ9KGGADWALF2TAOOC5EQCV5FHtzfnOiwAAAABJRU5ErkJggg==",
    "Township RP/textures/blocks/township_large_build_lot.png": "",
    "Township RP/textures/blocks/township_large_lot_marker.png": "",
    "Township RP/textures/blocks/township_lot_marker.png": "",
    "Township RP/textures/blocks/township_medium_build_lot.png": "",
    "Township RP/textures/blocks/township_medium_lot_marker.png": "",
    "Township RP/textures/blocks/township_small_build_lot.png": "iVBORw0KGgoAAAANSUhEUgAAABAAAAAQCAYAAAAf8/9hAAAAmUlEQVR4nGNUlhT6z0ABYGFgYGAIsZIhS/OaY08gBjAwMDDcf/aJJM2KUnwIF8AAFz8PUZq/ffwCZzORZC0WwIJL4kPXZThboEwXpwFYXfCh6zKDQJkuQ48uRDOyYUQZwMDAwFCz/TIKTbIBLZ66KDQugDUMYM4uuczAwAD1DkkGwAwhBlAcjdRNB8gpjGQDYGmbVMBIaXYGACkLJbDp/kG0AAAAAElFTkSuQmCC",
}

pattern = re.compile(
    r"=== SOURCE FILE BEGIN ===\n"
    r"PATH: (?P<path>[^\n]+)\n"
    r"KIND: [^\n]+\n"
    r"BYTES: [^\n]+\n"
    r"--- CONTENT ---\n"
    r"(?P<content>.*?)\n=== SOURCE FILE END ===",
    re.DOTALL,
)

source = MINER_FILE.read_text(encoding="utf-8")
written = []
for match in pattern.finditer(source):
    path = match.group("path")
    if not (path.startswith("Township BP/") or path.startswith("Township RP/")):
        continue
    target = Path(path)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(match.group("content") + "\n", encoding="utf-8", newline="\n")
    written.append(path)

for path, data in ASSETS.items():
    target = Path(path)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_bytes(base64.b64decode(data))

if not written:
    raise SystemExit("No source files were extracted from the miner library.")

print(f"Rebuilt {len(written)} text files and {len(ASSETS)} binary assets.")
